import{_ as t,o as e,c as i,O as s}from"./chunks/framework.bdcb0ee1.js";const m=JSON.parse('{"title":"Bulletins","description":"","frontmatter":{},"headers":[],"relativePath":"administration/config/bulletins.md","filePath":"administration/config/bulletins.md","lastUpdated":1773166478000}'),a={name:"administration/config/bulletins.md"},l=s('<h1 id="bulletins" tabindex="-1">Bulletins <a class="header-anchor" href="#bulletins" aria-label="Permalink to &quot;Bulletins&quot;">​</a></h1><p>Bulletins are dismissible announcements that you can display across your board. They&#39;re useful for sharing important updates, event notices, or time-sensitive information with your community.</p><p>You can manage bulletins from the <strong>Custom Content</strong> section in the Admin Control Panel.</p><nav class="table-of-contents"><ul><li><a href="#creating-a-bulletin">Creating a Bulletin</a></li><li><a href="#styles">Styles</a></li><li><a href="#positions">Positions</a></li><li><a href="#scheduling">Scheduling</a></li><li><a href="#group-targeting">Group Targeting</a></li><li><a href="#dismissals">Dismissals</a></li><li><a href="#notes">Notes</a></li></ul></nav><h2 id="creating-a-bulletin" tabindex="-1">Creating a Bulletin <a class="header-anchor" href="#creating-a-bulletin" aria-label="Permalink to &quot;Creating a Bulletin&quot;">​</a></h2><p>To create a new bulletin, go to <strong>Custom Content &gt; Bulletins</strong> and click <strong>Create Bulletin</strong>.</p><p>Fill in the following fields:</p><ul><li><strong>Title</strong>: A short heading for the bulletin (max 255 characters).</li><li><strong>Body</strong>: The main announcement content (max 10,000 characters). BBCode is supported.</li><li><strong>Style</strong>: Choose a visual style for the bulletin (see below).</li><li><strong>Custom CSS Class</strong>: If using the &quot;Custom CSS Class&quot; style, enter one or more CSS class names here. Only alphanumeric characters, spaces, dashes, and underscores are allowed.</li><li><strong>Dismissible</strong>: If enabled, users can dismiss the bulletin and it will not appear again for them.</li><li><strong>Active</strong>: Whether the bulletin is currently visible.</li><li><strong>Cached</strong>: When enabled, the bulletin content is cached for improved performance. Recommended for bulletins that don&#39;t change frequently.</li><li><strong>Position</strong>: Where the bulletin appears on the page.</li><li><strong>Priority</strong>: Controls the display order when multiple bulletins are active. Lower numbers appear first (0–999).</li><li><strong>Starts At</strong>: Optional. The date and time when the bulletin should start appearing.</li><li><strong>Ends At</strong>: Optional. The date and time when the bulletin should stop appearing. Must be after the start date.</li></ul><img width="1935" height="1854" alt="image" src="https://github.com/user-attachments/assets/49f99a9a-f1ed-44f0-b910-f39d4a19f1d1"><h2 id="styles" tabindex="-1">Styles <a class="header-anchor" href="#styles" aria-label="Permalink to &quot;Styles&quot;">​</a></h2><p>Bulletins support the following visual styles:</p><table><thead><tr><th>Style</th><th>Description</th></tr></thead><tbody><tr><td>Primary</td><td>Uses the board&#39;s primary colour scheme.</td></tr><tr><td>Accent</td><td>Uses the accent/highlight colour scheme.</td></tr><tr><td>Info</td><td>A neutral informational style.</td></tr><tr><td>Warning</td><td>A yellow/amber warning style.</td></tr><tr><td>Success</td><td>A green success/confirmation style.</td></tr><tr><td>Dark</td><td>A dark background with light text.</td></tr><tr><td>Light</td><td>A light background with dark text.</td></tr><tr><td>Custom CSS Class</td><td>Allows you to provide your own CSS class for full control.</td></tr></tbody></table><h2 id="positions" tabindex="-1">Positions <a class="header-anchor" href="#positions" aria-label="Permalink to &quot;Positions&quot;">​</a></h2><p>Choose where the bulletin appears on the page:</p><table><thead><tr><th>Position</th><th>Description</th></tr></thead><tbody><tr><td>Header Bar</td><td>Appears at the very top of the page, above all content.</td></tr><tr><td>Above Content</td><td>Appears above the main content area but below the navigation.</td></tr><tr><td>Below Content</td><td>Appears below the main content area.</td></tr></tbody></table><h2 id="scheduling" tabindex="-1">Scheduling <a class="header-anchor" href="#scheduling" aria-label="Permalink to &quot;Scheduling&quot;">​</a></h2><p>You can schedule bulletins to appear during a specific time window using the <strong>Starts At</strong> and <strong>Ends At</strong> fields. This is useful for event announcements, seasonal messages, or temporary notices.</p><ul><li>If only <strong>Starts At</strong> is set, the bulletin will appear from that date onwards.</li><li>If only <strong>Ends At</strong> is set, the bulletin will appear immediately and disappear at that date.</li><li>If both are set, the bulletin will only appear during that window.</li><li>If neither is set, the bulletin will appear immediately and remain visible until deactivated.</li></ul><h2 id="group-targeting" tabindex="-1">Group Targeting <a class="header-anchor" href="#group-targeting" aria-label="Permalink to &quot;Group Targeting&quot;">​</a></h2><p>By default, bulletins are visible to everyone. You can restrict visibility to specific user groups by selecting one or more groups when creating or editing a bulletin.</p><p>When groups are selected, only members of those groups will see the bulletin. This is useful for showing group-specific information, such as moderator notices or VIP announcements.</p><p>The guest group can also be targeted, allowing you to display bulletins specifically to non-logged-in visitors.</p><h2 id="dismissals" tabindex="-1">Dismissals <a class="header-anchor" href="#dismissals" aria-label="Permalink to &quot;Dismissals&quot;">​</a></h2><p>When a bulletin is marked as <strong>Dismissible</strong>, users can close it and it will not appear again for that user.</p><p>As an administrator, you can:</p><ul><li><strong>View Dismissals</strong>: See which users have dismissed a specific bulletin.</li><li><strong>Reset Dismissals</strong>: Re-show a dismissed bulletin to all users who previously closed it. This is useful if the bulletin content has been updated.</li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Multiple bulletins can be active at the same time. They are displayed in priority order.</li><li>Caching is recommended for bulletins with static content to reduce page load times.</li><li>Users who are not logged in cannot dismiss bulletins, so they will see dismissible bulletins on every visit.</li><li>Bulletins support BBCode formatting in the body field, so you can include links, bold text, and other formatting.</li></ul>',28),n=[l];function o(r,d,h,u,c,g){return e(),i("div",null,n)}const b=t(a,[["render",o]]);export{m as __pageData,b as default};
